// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertSame;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.lang.reflect.Constructor;
import java.lang.reflect.Method;
import java.util.List;

import org.junit.jupiter.api.Test;

class JoinCardinalityModelTest {

	@Test
	void stateModelCachesCanonicalSubsetPredicateCardinality() throws ReflectiveOperationException {
		Class<?> stateModelType = Class.forName(JoinCardinalityModel.class.getName() + "$StateModel");
		Constructor<?> constructor = stateModelType.getConstructor(double[].class, List.class);
		Method estimate = stateModelType.getMethod("estimate", JoinSubset.class, PredicateState.class);
		List<JoinCardinalityModel.PredicateTerm> predicates = List.of(
				JoinCardinalityModel.PredicateTerm.ordinary(LogSelectivity.fromLinear(0.5d), 0),
				JoinCardinalityModel.PredicateTerm.ordinary(LogSelectivity.fromLinear(0.1d), 1));
		Object model = constructor.newInstance(new double[] { 10.0d, 20.0d, 30.0d }, predicates);
		JoinSubset full = JoinSubset.ofOrdinals(0, 1, 2);
		PredicateState both = PredicateState.ofOrdinals(0, 1);

		JoinCardinalityModel.Estimate first = (JoinCardinalityModel.Estimate) estimate.invoke(model, full, both);
		JoinCardinalityModel.Estimate second = (JoinCardinalityModel.Estimate) estimate.invoke(model, full, both);
		JoinCardinalityModel.Estimate sparse = (JoinCardinalityModel.Estimate) estimate.invoke(model,
				JoinSubset.ofOrdinals(0, 2), PredicateState.ofOrdinals(1));

		assertEquals(300.0d, first.rows(), 1e-12);
		assertEquals(30.0d, sparse.rows(), 1e-12);
		assertSame(first, second, "One logical state must have one cached canonical estimate");
	}

	@Test
	void stateModelPreservesOneTypedEdgeEffectAcrossIndependentExtensions() {
		List<JoinCardinalityModel.PredicateTerm> edgeTerms = List.of(
				JoinCardinalityModel.PredicateTerm.ordinary(LogSelectivity.fromLinear(0.1d), 0));
		JoinCardinalityModel.StateModel model = new JoinCardinalityModel.StateModel(
				new double[] { 10.0d, 20.0d, 5.0d }, List.of(), edgeTerms);
		AppliedEdgeState applied = AppliedEdgeState.ofOrdinals(0);

		JoinCardinalityModel.Estimate typedPair = model.estimate(JoinSubset.ofOrdinals(0, 1), PredicateState.EMPTY,
				applied);
		JoinCardinalityModel.Estimate typedPairWithIndependentFactor = model.estimate(
				JoinSubset.ofOrdinals(0, 1, 2), PredicateState.EMPTY, applied);
		JoinCardinalityModel.Estimate unapplied = model.estimate(JoinSubset.ofOrdinals(0, 1, 2),
				PredicateState.EMPTY, AppliedEdgeState.EMPTY);

		assertEquals(20.0d, typedPair.rows(), 1e-12);
		assertEquals(100.0d, typedPairWithIndependentFactor.rows(), 1e-12,
				"An independent extension must retain the directed edge's effect exactly once");
		assertEquals(1_000.0d, unapplied.rows(), 1e-12,
				"Applied and unapplied edge states must not share one canonical estimate");
	}

	@Test
	void directionalSelectivityUsesLogDifference() {
		LogSelectivity selectivity = JoinCardinalityModel.directionalSelectivity(1e100d, false, 1e200d, 1e200d);

		assertTrue(selectivity.isPositive());
		assertEquals(-300.0d, selectivity.logValue() / Math.log(10.0d), 1e-12);
		assertEquals(1e-300d, selectivity.linearValue(), 1e-312d);
	}

	@Test
	void geometricMeanDoesNotUnderflow() {
		LogSelectivity mean = LogSelectivity.geometricMean(LogSelectivity.fromLinear(1e-300d),
				LogSelectivity.fromLinear(1e-200d));

		assertTrue(mean.isPositive());
		assertEquals(-250.0d, mean.logValue() / Math.log(10.0d), 1e-12);
		assertEquals(1e-250d, mean.linearValue(), 1e-262d);
	}

	@Test
	void nonExactZeroAndInvalidInputsAreUnavailable() {
		assertTrue(JoinCardinalityModel.directionalSelectivity(0.0d, false, 10.0d, 10.0d).isUnavailable());
		assertTrue(JoinCardinalityModel.directionalSelectivity(Double.NaN, false, 10.0d, 10.0d)
				.isUnavailable());
		assertTrue(LogSelectivity.fromLinear(Double.NaN).isUnavailable());
		assertTrue(LogSelectivity.fromLinear(-0.1d).isUnavailable());
	}

	@Test
	void exactZeroAndUnavailableEvidenceRemainDistinct() {
		JoinCardinalityModel.Estimate exactZero = JoinCardinalityModel.accumulator()
				.addBaseRows(0.0d)
				.addSelectivity(LogSelectivity.unavailable())
				.estimate();

		assertTrue(exactZero.exactZero());
		assertEquals(0.0d, exactZero.rows());
		assertEquals(1, exactZero.unavailableEvidenceCount());
	}

	@Test
	void sameEqualityClassUsesCanonicalMaximumSpanningForest() {
		List<JoinCardinalityModel.PredicateTerm> predicates = List.of(
				JoinCardinalityModel.PredicateTerm.equality(LogSelectivity.fromLinear(0.01d), "s", 0, 1, 0),
				JoinCardinalityModel.PredicateTerm.equality(LogSelectivity.fromLinear(0.9d), "s", 1, 2, 1),
				JoinCardinalityModel.PredicateTerm.equality(LogSelectivity.fromLinear(0.9d), "s", 0, 2, 2));

		JoinCardinalityModel.Estimate estimate = JoinCardinalityModel.estimate(new double[] { 1.0d, 1.0d, 1.0d },
				predicates);

		assertEquals(0.81d, estimate.rows(), 1e-12);
	}

	@Test
	void exactZeroEqualityProofCannotBeDiscardedByPositiveSpanningTree() {
		List<JoinCardinalityModel.PredicateTerm> predicates = List.of(
				JoinCardinalityModel.PredicateTerm.equality(LogSelectivity.exactZero(), "s", 0, 1, 0),
				JoinCardinalityModel.PredicateTerm.equality(LogSelectivity.fromLinear(0.9d), "s", 0, 2, 1),
				JoinCardinalityModel.PredicateTerm.equality(LogSelectivity.fromLinear(0.9d), "s", 1, 2, 2));

		JoinCardinalityModel.Estimate estimate = JoinCardinalityModel.estimate(new double[] { 1.0d, 1.0d, 1.0d },
				predicates);

		assertTrue(estimate.exactZero());
		assertEquals(0.0d, estimate.rows());
	}
}
